def product_share_rule(model, p, t):
    return model.x[p, t] <= 0.6 * sum(model.x[pp, t] for pp in model.p)
model.product_share = Constraint(model.p, model.t, rule=product_share_rule)

def min_each_rule(model, p, t):
    return model.x[p, t] >= 1
model.min_each = Constraint(model.p, model.t, rule=min_each_rule)
